local function clearESP()for _,v in pairs(espTable)do if v then v:Destroy()end end;espTable={}end
local function updateESP()clearESP();local plrs=p:GetPlayers()for _,v in ipairs(plrs)do if v~=plr then local root=gpo(v);local hum=gh(v);if root and hum and hum.Health>0 then local tcr=settings.esp.teamCheck and v.Team==plr.Team;if not tcr then if settings.esp.box then local box=wi("BoxHandleAdornment",{Parent=sg,Adornee=root,Size=Vector3.new(4,5,4),Color3=settings.esp.color,AlwaysOnTop=true,ZIndex=5,Transparency=0.5});table.insert(espTable,box)end;if settings.esp.chams then local c=wi("Highlight",{Parent=sg,Adornee=v.Character,FillColor=settings.esp.color,OutlineColor=Color3.fromRGB(255,255,255),FillTransparency=0.5});table.insert(espTable,c)end;if settings.esp.tracer then local t=wi("Attachment",{Parent=root,Position=root.Position});table.insert(espTable,t)end;if settings.esp.health and hum then local hl=wi("BillboardGui",{Parent=sg,Adornee=root,Size=UDim2.new(0,50,0,10),StudsOffset=Vector3.new(0,3,0)});wi("Frame",{Parent=hl,BackgroundColor3=Color3.fromRGB(0,255,0),BorderSizePixel=0,Size=UDim2.new(hum.Health/hum.MaxHealth,0,1,0)});table.insert(espTable,hl)end end end end end end
local function updateRadar()if not settings.radar.enabled or not radarFrame then return end;for _,d in pairs(radarDots)do d:Destroy()end;radarDots={};local lp=rl();if not lp then return end;local lpos=lp.Position;local lrot=lp.Orientation.Y;for _,v in ipairs(p:GetPlayers())do if v~=plr then local root=gpo(v);if root then local rpos=root.Position;local dx=rpos.X-lpos.X;local dz=rpos.Z-lpos.Z;local dist=math.sqrt(dx*dx+dz*dz);local ang=math.atan2(dx,dz)-math.rad(lrot);local sx=math.sin(ang)*dist*settings.radar.zoom;local sz=math.cos(ang)*dist*settings.radar.zoom;local hw=settings.radar.size/2;local cx=hw+sx;local cy=hw-sz;cx=math.clamp(cx,2,settings.radar.size-2);cy=math.clamp(cy,15,settings.radar.size-2);local dot=wi("Frame",{Parent=radarFrame,BackgroundColor3=v.Team==plr.Team and Color3.fromRGB(0,255,0)or Color3.fromRGB(255,0,0),BorderSizePixel=0,Size=UDim2.new(0,4,0,4),Position=UDim2.new(0,cx-2,0,cy-2)});table.insert(radarDots,dot)end end end end
rs.RenderStepped:Connect(function()if open and (settings.esp.box or settings.esp.chams or settings.esp.health)then updateESP()end;if settings.radar.enabled then updateRadar()end end)
local aimConn;local aimConnected=false;local function aimbot()local t=nil;local td=settings.aimbot.fov;local tc=mpos();local lp=rl();if not lp then return end;for _,v in ipairs(p:GetPlayers())do if v~=plr then local root=gpo(v);local hum=gh(v);if root and hum and hum.Health>0 then local tcr=settings.aimbot.teamCheck and v.Team==plr.Team;if not tcr then local scr=cam:WorldToViewportPoint(root.Position);if scr.Z>0 then local dist=(Vector2.new(scr.X,scr.Y)-tc).Magnitude;if dist<td then td=dist;t=v end end end end end end;if t then local root=gpo(t);if root then local rp=root.Position;if settings.aimbot.silent then local m=game:GetService("Players").LocalPlayer:GetMouse();if m then m.Hit=CFrame.new(cam.CFrame.Position,rp)end else cam.CFrame=cam.CFrame:Lerp(CFrame.new(cam.CFrame.Position,rp),settings.aimbot.smooth);if settings.aimbot.autoShoot then local tcp=root;local ig=tcp and tcp:FindFirstChild("Humanoid");if ig and ig.Health>0 then local dist2=(lp.Position-rp).Magnitude;if dist2<250 then VIM:SendMouseButtonEvent(0,0,0,true,nil,false);task.wait(0.05);VIM:SendMouseButtonEvent(0,0,0,false,nil,false)end end end end end end
local bp=0;rs.Heartbeat:Connect(function(dt)bp=bp+1;if bp%5==0 then if plr.Character and plr.Character:FindFirstChild("HumanoidRootPart")then local H=rh();if H then if settings.movement.bhop and uis:IsKeyDown(Enum.KeyCode.Space)then H:ChangeState(Enum.HumanoidStateType.Jumping)end;if settings.noclip then H:ChangeState(Enum.HumanoidStateType.Physics)end end;if settings.fly.enabled then local root=rl();if root then root.Velocity=Vector3.new(root.Velocity.X,0,root.Velocity.Z);local spd=settings.fly.speed;local mv=Vector3.new();if uis:IsKeyDown(Enum.KeyCode.W)then mv=mv+cam.CFrame.LookVector end;if uis:IsKeyDown(Enum.KeyCode.S)then mv=mv-cam.CFrame.LookVector end;if uis:IsKeyDown(Enum.KeyCode.A)then mv=mv-cam.CFrame.RightVector end;if uis:IsKeyDown(Enum.KeyCode.D)then mv=mv+cam.CFrame.RightVector end;mv=mv.Unit*spd;root.Velocity=Vector3.new(mv.X,0,mv.Z)end end;if settings.aimbot.enabled and not aimConnected then aimConnected=true;aimConn=rs.RenderStepped:Connect(aimbot)elseif not settings.aimbot.enabled and aimConnected then aimConnected=false;if aimConn then aimConn:Disconnect();aimConn=nil end end end;if bp%10==0 then local st="";local H=rh();if H then st="HP: "..math.floor(H.Health).." | "end;st=st..(settings.aimbot.enabled and"AIM "or"")..(settings.esp.box and"ESP "or"")..(settings.movement.bhop and"BHOP "or"")..(settings.fly.enabled and"FLY "or"")..(settings.noclip and"NOCLIP "or"")..(settings.infJump and"INFJ "or"");if st==""then st="AXME v2 - Ready"end;if statusText then statusText.Text=st end end end)
uis.JumpRequest:Connect(function()if settings.infJump and plr.Character and plr.Character:FindFirstChild("Humanoid")then plr.Character.Humanoid:ChangeState(Enum.HumanoidStateType.Jumping)end end)
local aaAng=0;rs.Stepped:Connect(function(_,dt)if settings.movement.antiaim and plr.Character and plr.Character:FindFirstChild("HumanoidRootPart")then local root=rl();if root then local tp=settings.movement.aaType;if tp=="jitter"then root.Orientation=Vector3.new(0,root.Orientation.Y+180,0)elseif tp=="spin"then aaAng=(aaAng+dt*360)%360;root.Orientation=Vector3.new(0,aaAng,0)elseif tp=="fake"then aaAng=(aaAng+dt*180)%360;root.Orientation=Vector3.new(0,aaAng,0)end end end;if settings.movement.airControl>0 and plr.Character and plr.Character:FindFirstChild("HumanoidRootPart")then local H=rh();if H and H:GetState()==Enum.HumanoidStateType.Freefall then local root=rl();if root then local mv=Vector3.new();if uis:IsKeyDown(Enum.KeyCode.W)then mv=mv+cam.CFrame.LookVector end;if uis:IsKeyDown(Enum.KeyCode.S)then mv=mv-cam.CFrame.LookVector end;if uis:IsKeyDown(Enum.KeyCode.A)then mv=mv-cam.CFrame.RightVector end;if uis:IsKeyDown(Enum.KeyCode.D)then mv=mv+cam.CFrame.RightVector end;if mv.Magnitude>0 then root.Velocity=root.Velocity+mv.Unit*(settings.movement.airControl*50*dt)end end end end end)
local function onChar(c)local H=c:WaitForChild("Humanoid");if H then H.WalkSpeed=settings.movement.ws;H.JumpPower=settings.movement.jp end end;plr.CharacterAdded:Connect(onChar);if plr.Character then onChar(plr.Character)end
